129:     /** The serializer used to write the TimeWindow type. */
130:     public static class Serializer extends TypeSerializerSingleton<TimeWindow> {
131:         private static final long serialVersionUID = 1L;
132: 
133:         @Override
134:         public boolean isImmutableType() {
135:             return true;
136:         }
